mapper.select:
SELECT id, withdraw_no, merchant_no, merchant_name, withdraw_amount, actual_amount, fee_amount, withdraw_type, withdraw_status, bank_name, bank_account, account_name, audit_user, audit_time, audit_remark, transfer_no, transfer_channel, channel_transfer_no, transfer_time, transfer_fail_reason, transfer_retry_count, next_transfer_retry_time, arrive_time, remark, created_at, updated_at, deleted FROM merchant_withdraw
deleted = 0
AND withdraw_no = #{params.withdrawNo}
AND merchant_no = #{params.merchantNo}
AND merchant_name LIKE CONCAT('%', #{params.merchantName}, '%')
AND withdraw_status = #{params.withdrawStatus}
AND withdraw_type = #{params.withdrawType}
AND created_at >= #{params.startDate}
AND created_at <= #{params.endDate}
ORDER BY created_at DESC

SELECT COALESCE(SUM(withdraw_amount), 0)
FROM merchant_withdraw
WHERE deleted = 0
  AND merchant_no = #{merchantNo}

      AND withdraw_status = #{withdrawStatus}
